class _NoRedirect(urllib.request.HTTPRedirectHandler):
    def redirect_request(self, req, fp, code, msg, headers, newurl):
        return None


def _host_allowed(host: str, policy: FetchPolicy) -> bool:
    host_l = host.lower().rstrip(".")
    if policy.allowed_hosts is not None:
        if host_l not in {h.lower().rstrip(".") for h in policy.allowed_hosts}:
            return False
    if policy.allowed_host_suffixes is not None:
        if not any(host_l == s.lower().lstrip(".").rstrip(".") or host_l.endswith("." + s.lower().lstrip(".").rstrip("."))
                   for s in policy.allowed_host_suffixes):
            return False
    return True


def _is_ip_blocked(ip: ipaddress._BaseAddress, policy: FetchPolicy) -> bool:
    if policy.block_private_ips and ip.is_private:
        return True
    if policy.block_loopback and ip.is_loopback:
        return True
    if policy.block_link_local and ip.is_link_local:
        return True
    if policy.block_multicast and ip.is_multicast:
        return True
    if ip.is_unspecified:
        return True
    if getattr(ip, "is_reserved", False):
        return True
    return False


def _validate_url(url: str, policy: FetchPolicy) -> urllib.parse.SplitResult:
    if not isinstance(url, str) or not url.strip():
        raise ValueError("URL must be a non-empty string")

    parsed = urllib.parse.urlsplit(url.strip())
    if parsed.scheme.lower() not in policy.allowed_schemes:
        raise ValueError("URL scheme not allowed")

    if not policy.allow_userinfo and (parsed.username is not None or parsed.password is not None):
        raise ValueError("Userinfo in URL is not allowed")

    if not policy.allow_query and parsed.query:
        raise ValueError("Query parameters are not allowed")

    if not parsed.hostname:
        raise ValueError("URL must include a hostname")

    if not _host_allowed(parsed.hostname, policy):
        raise ValueError("Host not allowed")

    port = parsed.port
    if port is None:
        if parsed.scheme.lower() == "https":
            port = 443
        elif parsed.scheme.lower() == "http":
            port = 80

    if port is None or port not in policy.allowed_ports:
        raise ValueError("Port not allowed")

    if policy.block_private_ips:
        try:
            ip = ipaddress.ip_address(parsed.hostname)
        except ValueError:
            ip = None
        if ip is not None and _is_ip_blocked(ip, policy):
            raise ValueError("IP address is blocked")

    return parsed


def fetch_url_content(
    url: str,
    *,
    policy: Optional[FetchPolicy] = None,
    headers: Optional[Mapping[str, str]] = None,
) -> Dict[str, Any]:
    policy = policy or FetchPolicy()
    _validate_url(url, policy)

    req_headers = {
        "User-Agent": policy.user_agent,
        "Accept": "*/*",
    }
    if headers:
        for k, v in headers.items():
            if k and v is not None:
                req_headers[str(k)] = str(v)

    request = urllib.request.Request(url, headers=req_headers, method="GET")

    opener = urllib.request.build_opener(_NoRedirect()) if not policy.follow_redirects else urllib.request.build_opener()
    with opener.open(request, timeout=policy.timeout_seconds) as resp:
        status = getattr(resp, "status", None) or resp.getcode()
        resp_headers = dict(resp.headers.items())

        remaining = policy.max_bytes
        chunks = []
        while remaining > 0:
            chunk = resp.read(min(65536, remaining))
            if not chunk:
                break
            chunks.append(chunk)
            remaining -= len(chunk)

        body = b"".join(chunks)

    content_type = resp_headers.get("Content-Type", "")
    charset = "utf-8"
    if "charset=" in content_type.lower():
        charset = content_type.lower().split("charset=", 1)[1].split(";", 1)[0].strip() or "utf-8"

    text = body.decode(charset, errors="replace")

    return {
        "url": url,
        "status": int(status),
        "headers": resp_headers,
        "content_type": content_type,
        "charset": charset,
        "bytes": len(body),
        "text": text,
    }


def display_url_content(
    url: Optional[str] = None,
    *,
    policy: Optional[FetchPolicy] = None,
    headers: Optional[Mapping[str, str]] = None,
    max_print_chars: int = 20000,
) -> None:
    if url is None:
        url = input("Enter URL: ").strip()

    result = fetch_url_content(url, policy=policy, headers=headers)

    print(f"URL: {result['url']}")
    print(f"Status: {result['status']}")
    print(f"Bytes: {result['bytes']}")
    ct = result.get("content_type") or ""
    if ct:
        print(f"Content-Type: {ct}")
    print("---")
    text = result["text"]
    if max_print_chars is not None and max_print_chars >= 0 and len(text) > max_print_chars:
        print(text[:max_print_chars])
        print("\n---\n[truncated]")
    else:
        print(text)


def fetch_partner_resource(
    partner: str,
    config: Mapping[str, Any],
    *,
    policy: Optional[FetchPolicy] = None,
) -> Dict[str, Any]:
    if not isinstance(config, Mapping):
        raise ValueError("config must be a mapping")
    if not isinstance(partner, str) or not partner.strip():
        raise ValueError("partner must be a non-empty string")

    url = config.get("url")
    if not url:
        raise ValueError("config must include 'url'")

    headers = config.get("headers") or {}
    if not isinstance(headers, Mapping):
        raise ValueError("'headers' must be a mapping")

    auth = config.get("auth") or {}
    if not isinstance(auth, Mapping):
        raise ValueError("'auth' must be a mapping")

    final_headers: Dict[str, str] = {str(k): str(v) for k, v in headers.items()}

    auth_type = str(auth.get("type") or "").lower()
    if auth_type == "bearer":
        token = auth.get("token")
        if token:
            final_headers.setdefault("Authorization", f"Bearer {token}")
    elif auth_type == "basic":
        user = auth.get("username")
        pwd = auth.get("password")
        if user is not None and pwd is not None:
            import base64
            b64 = base64.b64encode(f"{user}:{pwd}".encode("utf-8")).decode("ascii")
            final_headers.setdefault("Authorization", f"Basic {b64}")

    result = fetch_url_content(url, policy=policy, headers=final_headers)
    result["partner"] = partner
    return result


def handle_webhook_event(
    event: Union[str, bytes, Mapping[str, Any]],
    *,
    policy: Optional[FetchPolicy] = None,
) -> Dict[str, Any]:
    if isinstance(event, (str, bytes)):
        event_obj = json.loads(event)
    elif isinstance(event, Mapping):
        event_obj = dict(event)
    else:
        raise ValueError("event must be JSON string/bytes or a mapping")

    partner = event_obj.get("partner") or event_obj.get("source") or "unknown"
    config = event_obj.get("config") or {}
    if not isinstance(config, Mapping):
        raise ValueError("event.config must be a mapping")

    return fetch_partner_resource(str(partner), config, policy=policy)